// src/pages/Leave/LeavePage.js

import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Bell, RefreshCw, Users,
  TrendingUp, AlertTriangle, ArrowRightLeft, Shield, RotateCcw, Edit3
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI, notificationAPI } from '../../api/services';
import { Modal, SkeletonCard, EmptyState, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';

const STATUS_OPTIONS = [
  { value: '', label: 'All' },
  { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending Approval' },
  { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' },
  { value: 'CANCELLED', label: 'Cancelled' },
];

const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');
const statusMatches = (reqStatus, filterValue) => {
  if (!filterValue) return true;
  return normStatus(reqStatus) === normStatus(filterValue);
};
const isFinalStatus = s => ['APPROVED', 'REJECTED', 'CANCELLED'].includes(normStatus(s));

// ─── Balance Card ────────────────────────────────────────────────────────────
function BalanceCard({ balance, loading }) {
  if (loading) return <SkeletonCard />;
  const name = balance.leaveTypeName || balance.LeaveType?.LeaveTypeName || 'Leave';
  const used = Number(balance.UsedDays || 0);
  const pending = Number(balance.PendingDays || 0);
  const entitled = Number(balance.EntitledDays || 0);
  const carryOver = Number(balance.CarryOverDays || 0);
  const maxDays = entitled + carryOver;
  const remaining = Math.max(0, maxDays - used - pending);
  const pct = maxDays > 0 ? Math.round((remaining / maxDays) * 100) : 0;

  return (
    <div className="stat-card" style={{ padding: '1.5rem', background: '#fff', borderRadius: '8px', border: '1px solid #eee' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ fontWeight: 600 }}>{name}</div>
        <CalendarDays size={18} color="var(--primary)" />
      </div>
      <div style={{ fontSize: '2rem', fontWeight: 700, color: 'var(--primary)' }}>{remaining}</div>
      <div style={{ fontSize: '0.8rem', color: '#666' }}>days remaining of {maxDays}</div>
      <div style={{ marginTop: '1rem', fontSize: '0.8rem', color: '#888' }}>
        Used: {used} | Pending: {pending}
      </div>
    </div>
  );
}

// ─── Submit Leave Form ───────────────────────────────────────────────────────
function SubmitLeaveForm({ leaveTypes, onSubmit, loading }) {
  const [form, setForm] = useState({ LeaveTypeID: '', startDate: '', endDate: '', reason: '' });

  const handle = () => {
    if (!form.LeaveTypeID || !form.startDate || !form.endDate) {
      return toast.error("Please fill in all required fields.");
    }

    // STRICT PASCAL CASE TO MATCH YOUR JOI VALIDATION
    const payload = {
      LeaveTypeID: parseInt(form.LeaveTypeID, 10),
      StartDate: new Date(form.startDate).toISOString(),
      EndDate: new Date(form.endDate).toISOString(),
      IsHalfDay: false, 
      Reason: form.reason || null
    };

    onSubmit(payload);
  };

  return (
    <>
      <div className="form-group mb-4">
        <label className="form-label required">Leave Type</label>
        <select className="form-select w-full p-2 border rounded" value={form.LeaveTypeID} onChange={e => setForm({...form, LeaveTypeID: e.target.value})}>
          <option value="">— Select a leave type —</option>
          {leaveTypes.map(t => (
            <option key={t.LeaveTypeID} value={t.LeaveTypeID}>{t.LeaveTypeName}</option>
          ))}
        </select>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
        <div>
          <label className="form-label required">Start Date</label>
          <input className="form-input w-full p-2 border rounded" type="date" value={form.startDate} onChange={e => setForm({...form, startDate: e.target.value})} />
        </div>
        <div>
          <label className="form-label required">End Date</label>
          <input className="form-input w-full p-2 border rounded" type="date" min={form.startDate} value={form.endDate} onChange={e => setForm({...form, endDate: e.target.value})} />
        </div>
      </div>
      <div className="form-group mb-4">
        <label className="form-label">Reason</label>
        <textarea className="form-textarea w-full p-2 border rounded" rows={3} value={form.reason} onChange={e => setForm({...form, reason: e.target.value})} />
      </div>
      <div style={{ display: 'flex', justifyItems: 'flex-end', marginTop: 16 }}>
        <button className="btn btn-primary px-4 py-2 bg-blue-600 text-white rounded" onClick={handle} disabled={loading}>
          {loading ? 'Submitting...' : 'Submit Request'}
        </button>
      </div>
    </>
  );
}

// ─── MAIN LEAVE PAGE COMPONENT ───────────────────────────────────────────────
export default function LeavePage() {
  const { user } = useAuth();

  const roleStr = (user?.role || '').toUpperCase();
  const isManager = roleStr.includes('MANAGER') || roleStr.includes('ADMIN') || roleStr.includes('HR');
  const isHR = roleStr.includes('HR') || roleStr.includes('ADMIN');

  const [tab, setTab] = useState('history');
  const [myRequests, setMyRequests] = useState([]);
  const [balances, setBalances] = useState([]);
  const [leaveTypes, setLeaveTypes] = useState([]);

  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [filterStatus, setFilterStatus] = useState('');

  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);

  // ─── BUG 1 FIX: FAULT-TOLERANT DATA LOADING ────────────────────────────────
  const loadDashboardData = useCallback(async () => {
    setLoading(true);

    // Construct params cleanly. If filterStatus is empty, DO NOT send it.
    const queryParams = {};
    if (filterStatus) queryParams.status = filterStatus;

    try {
      // 1. Fetch Types
      try {
        const typeRes = await leaveAPI.getTypes();
        setLeaveTypes(typeRes.data || []);
      } catch (e) { console.warn("Could not fetch leave types"); }

      // 2. Fetch Balances
      try {
        const balRes = await leaveAPI.getMyBalances();
        setBalances(balRes.data || []);
      } catch (e) { console.warn("Could not fetch balances"); }

      // 3. Fetch Requests (Using the safe queryParams)
      try {
        const reqRes = await leaveAPI.getMyRequests(queryParams);
        setMyRequests(reqRes.data?.requests || reqRes.data || []);
      } catch (e) { 
        console.error("Fetch requests failed:", e.response?.data);
        toast.error("Failed to load requests from server."); 
      }

    } finally {
      setLoading(false);
    }
  }, [filterStatus]);

  useEffect(() => {
    loadDashboardData();
  }, [loadDashboardData]);

  // ─── BUG 2 FIX: ROBUST SUBMIT HANDLER ──────────────────────────────────────
  const handleSubmitLeave = async (payload) => {
    setActionLoading(true);
    try {
      await leaveAPI.submit(payload);
      toast.success("Leave request submitted successfully");
      setIsSubmitModalOpen(false);
      await loadDashboardData();
    } catch (err) { 
      // This will literally tell you what Joi rejected
      console.error("SUBMIT REJECTED BY BACKEND:", err.response?.data);
      const backendMessage = err.response?.data?.message || err.response?.data?.error || err.message;
      toast.error(`Validation Error: ${backendMessage}`); 
    } finally { 
      setActionLoading(false); 
    }
  };

  const handleCancelRequest = async (id) => {
    const reason = window.prompt("Reason for cancellation:");
    if (!reason) return;
    setActionLoading(true);
    try {
      await leaveAPI.cancel(id, { CancelReason: reason }); 
      toast.success("Request cancelled");
      await loadDashboardData();
    } catch (err) { toast.error("Failed to cancel request"); } 
    finally { setActionLoading(false); }
  };

  if (loading && myRequests.length === 0 && balances.length === 0) return <div className="p-8">Loading HR Data...</div>;

  return (
    <div className="leave-module" style={{ padding: '2rem' }}>

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <div>
          <h1 style={{ fontSize: '1.875rem', fontWeight: 700 }}>Leave Management</h1>
          <p style={{ color: '#666' }}>Track balances and submit requests.</p>
        </div>
        <button className="btn btn-primary px-4 py-2 bg-blue-600 text-white rounded flex items-center gap-2" onClick={() => setIsSubmitModalOpen(true)}>
          <Plus size={18} /> New Request
        </button>
      </div>

      {/* Balances */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem', marginBottom: '2.5rem' }}>
        {balances.length > 0 ? balances.map((bal) => (
          <BalanceCard key={bal.LeaveTypeID} balance={bal} loading={false} />
        )) : (
          <div style={{ padding: '1rem', background: '#fef3c7', color: '#92400e', borderRadius: '8px' }}>
            No leave balances found. Your HR Admin needs to initialize your yearly balance.
          </div>
        )}
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: '2rem', borderBottom: '1px solid #ddd', marginBottom: '1.5rem' }}>
        <button style={{ paddingBottom: '1rem', borderBottom: '2px solid #2563eb', fontWeight: 600, color: '#2563eb' }}>
          My Leave History
        </button>
        {isManager && <button style={{ paddingBottom: '1rem', color: '#666' }}>Team Inbox (Manager)</button>}
        {isHR && <button style={{ paddingBottom: '1rem', color: '#666' }}>HR Dashboard</button>}
      </div>

      {/* History Panel */}
      <div style={{ background: '#fff', borderRadius: '8px', border: '1px solid #eee' }}>
        <div style={{ padding: '1rem', display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid #eee' }}>
          <h3 style={{ fontWeight: 600 }}>My Leave History</h3>
          <div style={{ display: 'flex', gap: '10px' }}>
              <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} style={{ padding: '0.25rem 0.5rem', border: '1px solid #ccc', borderRadius: '4px' }}>
                {STATUS_OPTIONS.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
              </select>
              <button onClick={loadDashboardData} style={{ padding: '0.25rem' }}><RefreshCw size={18} /></button>
          </div>
        </div>
        <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
          <thead>
            <tr style={{ borderBottom: '1px solid #eee', color: '#666' }}>
              <th style={{ padding: '1rem' }}>Type</th>
              <th style={{ padding: '1rem' }}>Dates</th>
              <th style={{ padding: '1rem' }}>Status</th>
              <th style={{ padding: '1rem' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {myRequests.map((req) => (
              <tr key={req.LeaveRequestID} style={{ borderBottom: '1px solid #eee' }}>
                <td style={{ padding: '1rem', fontWeight: 500 }}>{req.LeaveType?.LeaveTypeName || 'Leave'}</td>
                <td style={{ padding: '1rem' }}>{new Date(req.StartDate).toLocaleDateString()} - {new Date(req.EndDate).toLocaleDateString()}</td>
                <td style={{ padding: '1rem' }}>{req.Status}</td>
                <td style={{ padding: '1rem' }}>
                  {!isFinalStatus(req.Status) && (
                    <button onClick={() => handleCancelRequest(req.LeaveRequestID)} style={{ color: '#dc2626', fontSize: '0.9rem' }}>Cancel</button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {myRequests.length === 0 && <div style={{ padding: '2rem', textAlign: 'center', color: '#666' }}>No requests found.</div>}
      </div>

      {isSubmitModalOpen && (
        <Modal title="Submit Leave Request" onClose={() => setIsSubmitModalOpen(false)}>
          <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmitLeave} loading={actionLoading} />
        </Modal>
      )}
    </div>
  );
}
